import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../context/AuthContext';

export default function StudentProfile() {
  const { user, updateProfile } = useAuth();
  const [form, setForm] = useState({ name: user?.name || '', bio: user?.bio || '' });
  const [saving, setSaving] = useState(false);
  const [activeTab, setActiveTab] = useState('profile');

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await updateProfile(form);
      toast.success('Profile updated!');
    } catch {
      toast.error('Failed to update');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="page-wrapper" style={{ background: 'var(--bg-primary)', minHeight: '100vh' }}>
      <div className="container" style={{ maxWidth: 720, margin: '0 auto', padding: '32px 20px' }}>

        {/* ENHANCED HEADER */}
        <div className="page-header" style={{ marginBottom: 32 }}>
          <div style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'flex-start',
            flexWrap: 'wrap',
            gap: '16px'
          }}>
            <div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '8px' }}>
                <div style={{ 
                  width: '48px', 
                  height: '48px', 
                  background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))',
                  borderRadius: 'var(--radius-md)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '24px'
                }}>
                  👤
                </div>
                <div>
                  <h2 style={{ fontFamily: 'var(--font-display)', margin: 0, fontSize: '1.75rem' }}>
                    MY <span className="gradient-text">PROFILE</span>
                  </h2>
                  <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem', marginTop: '4px' }}>
                    Manage your account information and preferences
                  </p>
                </div>
              </div>
            </div>
            <Link to="/student" className="btn btn-outline" style={{ 
              display: 'flex',
              alignItems: 'center',
              gap: '8px'
            }}>
              <span>←</span> Dashboard
            </Link>
          </div>
        </div>

        {/* ENHANCED CARD */}
        <div
          className="card"
          style={{
            padding: 0,
            borderRadius: 'var(--radius-lg)',
            boxShadow: '0 8px 32px rgba(0,0,0,0.2)',
            overflow: 'hidden',
            background: 'var(--bg-secondary)',
            border: '1px solid rgba(255,255,255,0.05)'
          }}
        >

          {/* PROFILE HEADER WITH COVER */}
          <div style={{ position: 'relative' }}>
            {/* Cover Image */}
            <div style={{ 
              height: '120px', 
              background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent), var(--cyan-accent))',
              position: 'relative'
            }} />

            {/* Profile Info */}
            <div style={{ 
              padding: '0 32px 32px 32px',
              marginTop: '-60px',
              position: 'relative'
            }}>
              <div style={{ 
                display: 'flex', 
                alignItems: 'flex-end',
                gap: '24px',
                flexWrap: 'wrap'
              }}>
                {/* Enhanced Avatar */}
                <div
                  className="avatar avatar-xl"
                  style={{
                    width: '120px',
                    height: '120px',
                    fontSize: '3rem',
                    boxShadow: '0 8px 24px rgba(0,0,0,0.3)',
                    border: '4px solid var(--bg-secondary)',
                    background: 'linear-gradient(135deg, var(--purple-primary), var(--cyan-accent))',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    borderRadius: '50%'
                  }}
                >
                  {user?.name?.charAt(0)}
                </div>

                <div style={{ flex: 1, marginBottom: '8px' }}>
                  <div
                    style={{
                      fontFamily: 'var(--font-display)',
                      fontSize: '1.8rem',
                      marginBottom: '8px',
                      fontWeight: 'bold'
                    }}
                  >
                    {user?.name}
                  </div>

                  <div
                    style={{
                      fontFamily: 'var(--font-mono)',
                      fontSize: '0.9rem',
                      color: 'var(--cyan-accent)',
                      marginBottom: '12px',
                      display: 'flex',
                      alignItems: 'center',
                      gap: '8px'
                    }}
                  >
                    <span>📋</span> {user?.itNumber}
                  </div>

                  <div style={{ display: 'flex', gap: '12px', flexWrap: 'wrap' }}>
                    <span className="badge badge-student" style={{ 
                      background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                      padding: '6px 12px'
                    }}>🎓 Student</span>
                    <span className="badge badge-approved" style={{ 
                      background: user?.status === 'approved' ? 'linear-gradient(135deg, #10b981, #059669)' : 'var(--warning)',
                      padding: '6px 12px'
                    }}>{user?.status === 'approved' ? '✓ Approved' : '⏳ Pending'}</span>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {/* TABS */}
          <div style={{ 
            borderBottom: '1px solid rgba(255,255,255,0.1)',
            padding: '0 32px',
            display: 'flex',
            gap: '32px'
          }}>
            {[
              { id: 'profile', label: 'Profile Information', icon: '👤' },
              { id: 'security', label: 'Security', icon: '🔒' }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                style={{
                  padding: '12px 0',
                  background: 'none',
                  border: 'none',
                  color: activeTab === tab.id ? 'var(--purple-light)' : 'var(--text-muted)',
                  cursor: 'pointer',
                  fontSize: '0.9rem',
                  fontWeight: activeTab === tab.id ? '600' : '400',
                  borderBottom: activeTab === tab.id ? `2px solid var(--purple-light)` : '2px solid transparent',
                  transition: 'all 0.2s',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px'
                }}
              >
                <span>{tab.icon}</span> {tab.label}
              </button>
            ))}
          </div>

          {/* FORM CONTENT */}
          <div style={{ padding: '32px' }}>
            {activeTab === 'profile' && (
              <form onSubmit={handleSave}>
                {/* Enhanced Input Groups */}
                <div className="form-group" style={{ marginBottom: '24px' }}>
                  <label className="form-label" style={{ 
                    display: 'flex', 
                    alignItems: 'center', 
                    gap: '8px',
                    marginBottom: '8px',
                    fontWeight: '500'
                  }}>
                    <span>✏️</span> Full Name
                  </label>
                  <input
                    className="form-control"
                    value={form.name}
                    onChange={e => setForm(p => ({ ...p, name: e.target.value }))}
                    required
                    style={{ 
                      transition: '0.2s ease',
                      border: '1px solid rgba(255,255,255,0.1)',
                      background: 'var(--bg-elevated)',
                      padding: '12px'
                    }}
                    placeholder="Enter your full name"
                  />
                </div>

                <div className="form-group" style={{ marginBottom: '24px' }}>
                  <label className="form-label" style={{ 
                    display: 'flex', 
                    alignItems: 'center', 
                    gap: '8px',
                    marginBottom: '8px',
                    fontWeight: '500'
                  }}>
                    <span>📧</span> Email Address
                  </label>
                  <div style={{ position: 'relative' }}>
                    <input
                      className="form-control"
                      value={user?.email || ''}
                      disabled
                      style={{ 
                        opacity: 0.6,
                        background: 'rgba(255,255,255,0.05)',
                        padding: '12px',
                        cursor: 'not-allowed'
                      }}
                    />
                    <span style={{ 
                      position: 'absolute',
                      right: '12px',
                      top: '50%',
                      transform: 'translateY(-50%)',
                      fontSize: '12px',
                      color: 'var(--text-muted)'
                    }}>🔒 Verified</span>
                  </div>
                </div>

                <div className="form-group" style={{ marginBottom: '24px' }}>
                  <label className="form-label" style={{ 
                    display: 'flex', 
                    alignItems: 'center', 
                    gap: '8px',
                    marginBottom: '8px',
                    fontWeight: '500'
                  }}>
                    <span>📋</span> IT Number
                  </label>
                  <div style={{ position: 'relative' }}>
                    <input
                      className="form-control"
                      value={user?.itNumber || ''}
                      disabled
                      style={{
                        opacity: 0.6,
                        background: 'rgba(255,255,255,0.05)',
                        fontFamily: 'var(--font-mono)',
                        padding: '12px',
                        cursor: 'not-allowed'
                      }}
                    />
                    <span style={{ 
                      position: 'absolute',
                      right: '12px',
                      top: '50%',
                      transform: 'translateY(-50%)',
                      fontSize: '12px',
                      color: 'var(--text-muted)'
                    }}>🔒 Immutable</span>
                  </div>
                </div>

                <div className="form-group" style={{ marginBottom: '32px' }}>
                  <label className="form-label" style={{ 
                    display: 'flex', 
                    alignItems: 'center', 
                    gap: '8px',
                    marginBottom: '8px',
                    fontWeight: '500'
                  }}>
                    <span>📝</span> Bio
                  </label>
                  <textarea
                    className="form-control"
                    rows={4}
                    value={form.bio}
                    onChange={e => setForm(p => ({ ...p, bio: e.target.value }))}
                    placeholder="Tell us about yourself, your interests, and goals..."
                    style={{
                      resize: 'vertical',
                      transition: '0.2s ease',
                      border: '1px solid rgba(255,255,255,0.1)',
                      background: 'var(--bg-elevated)',
                      padding: '12px',
                      lineHeight: '1.6'
                    }}
                  />
                </div>

                {/* Enhanced Save Button */}
                <button
                  type="submit"
                  className="btn btn-primary"
                  style={{
                    width: '100%',
                    justifyContent: 'center',
                    padding: '14px',
                    fontSize: '1rem',
                    fontWeight: 600,
                    transition: 'all 0.2s ease',
                    transform: saving ? 'scale(0.98)' : 'scale(1)',
                    background: 'linear-gradient(135deg, var(--purple-primary), var(--pink-accent))',
                    border: 'none',
                    borderRadius: 'var(--radius-md)',
                    cursor: saving ? 'not-allowed' : 'pointer'
                  }}
                  disabled={saving}
                >
                  {saving ? (
                    <span style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                      <span className="spinner" style={{ width: '16px', height: '16px', borderWidth: '2px' }} />
                      Saving...
                    </span>
                  ) : (
                    <span style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}>
                      💾 Save Profile Changes
                    </span>
                  )}
                </button>
              </form>
            )}

            {activeTab === 'security' && (
              <div style={{ textAlign: 'center', padding: '40px 20px' }}>
                <div style={{ 
                  fontSize: '3rem', 
                  marginBottom: '16px',
                  opacity: 0.5
                }}>
                  🔒
                </div>
                <h3 style={{ marginBottom: '8px', color: 'var(--text-primary)' }}>Security Settings</h3>
                <p style={{ color: 'var(--text-secondary)', marginBottom: '24px' }}>
                  Password management and security preferences
                </p>
                <button
                  className="btn btn-outline"
                  style={{ 
                    padding: '10px 24px',
                    borderColor: 'var(--purple-light)',
                    color: 'var(--purple-light)'
                  }}
                  onClick={() => toast.info('Feature coming soon!')}
                >
                  Change Password →
                </button>
              </div>
            )}
          </div>

          {/* Additional Stats Section */}
          <div style={{ 
            borderTop: '1px solid rgba(255,255,255,0.1)',
            padding: '24px 32px',
            background: 'var(--bg-elevated)',
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
            gap: '24px'
          }}>
            <div>
              <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginBottom: '4px' }}>Member Since</div>
              <div style={{ fontWeight: '600', fontSize: '0.9rem' }}>
                {new Date(user?.createdAt).toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
              </div>
            </div>
            <div>
              <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginBottom: '4px' }}>Account Status</div>
              <div style={{ fontWeight: '600', fontSize: '0.9rem', color: user?.status === 'approved' ? '#10b981' : 'var(--warning)' }}>
                {user?.status === 'approved' ? 'Active ✓' : 'Pending Approval'}
              </div>
            </div>
            <div>
              <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginBottom: '4px' }}>Last Updated</div>
              <div style={{ fontWeight: '600', fontSize: '0.9rem' }}>
                {new Date(user?.updatedAt).toLocaleDateString()}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
